// Check if this is Microsoft's validation request
const incomingData = $input.item.json;

console.log('🔔 Webhook received');

const validationToken = incomingData.validationToken || incomingData.query?.validationToken;

if (validationToken) {
  console.log('✅ Validation request detected');
  return {
    json: {
      isValidation: true,
      validationToken: validationToken
    }
  };
}

console.log('📧 Email notification detected');
return {
  json: {
    isValidation: false,
    rawData: incomingData
  }
};

// Simple Deduplication - Process only FIRST 'created' event per message
const rawData = $input.item.json.rawData;

// Handle BOTH nested and direct structures
let notifications = [];
if (Array.isArray(rawData.body)) {
  // Nested structure: body is an array
  notifications = rawData.body?.[0]?.body?.value || [];
} else if (rawData.body?.value) {
  // Direct structure: body is an object with value array
  notifications = rawData.body.value;
} else {
  notifications = [];
}

console.log(`📬 Processing ${notifications.length} notification(s)`);

if (notifications.length === 0) {
  console.log('⚠️  No notifications found in webhook payload');
  return [];
}

const results = [];
const seenMessages = new Set(); // Track within this batch

for (const notification of notifications) {
  const subscriptionId = notification.subscriptionId;
  const clientState = notification.clientState; // user_id
  const resourceData = notification.resourceData || {};
  const messageId = resourceData.id;
  const changeType = notification.changeType;

  const dedupeKey = `${clientState}_${messageId}`;

  console.log(`📧 Notification:`);
  console.log(`   User ID: ${clientState}`);
  console.log(`   Message ID: ${messageId}`);
  console.log(`   Change Type: ${changeType}`);

  // FILTER 1: Only process 'created' events
  if (changeType !== 'created') {
    console.log(`   ⏭️  Skipping ${changeType} event`);
    continue;
  }

  // FILTER 2: Skip if already seen in this batch
  if (seenMessages.has(dedupeKey)) {
    console.log(`   ⏭️  Duplicate in batch - skipping`);
    continue;
  }

  if (messageId && clientState) {
    seenMessages.add(dedupeKey);
    console.log(`   ✅ Processing email`);
    results.push({
      json: {
        user_id: clientState,
        message_id: messageId,
        subscription_id: subscriptionId
      }
    });
  } else {
    console.log('   ⚠️  Missing required fields');
  }
}

console.log(`✅ Returning ${results.length} unique result(s)`);
return results;

// Format for AI (keeping your logic)
const guardrailsInput = $input.item.json.guardrailsInput;
const emailData = $('Prepare_Email_Data').item.json;

const lines = guardrailsInput.split('\n');
let subject = '';
let from = '';
let domain = '';
let preview = '';

for (let i = 0; i < lines.length; i++) {
  const line = lines[i];
  if (line.startsWith('Subject: ')) subject = line.replace('Subject: ', '').trim();
  else if (line.startsWith('From: ')) from = line.replace('From: ', '').trim();
  else if (line.startsWith('Domain: ')) domain = line.replace('Domain: ', '').trim();
  else if (line.startsWith('Preview: ')) {
    preview = lines.slice(i).join('\n').replace('Preview: ', '').trim();
    break;
  }
}

const aiPrompt = `Classify this email:

Subject: ${subject}
From: ${from}
Domain: ${domain}
Preview: ${preview}

Categories:
- URGENT: Critical, time-sensitive matters
- TO_REPLY: Requires response
- ACTION_REQUIRED: Needs action/tasks
- MEETING_SUMMARY: Meeting notes
- JAGGAER: JAGGAER system emails
- FYI: Informational only
- PROMOTIONAL: Marketing/newsletters

Respond with JSON:
{
  "category": "CATEGORY_NAME",
  "reason": "Brief explanation",
  "confidence": 0.95
}`;

return {
  json: {
    subject: subject,
    aiPrompt: aiPrompt,
    emailId: emailData.emailId,
    userId: emailData.userId,
    userEmail: emailData.userEmail,
    accessToken: emailData.accessToken
  }
};

// Parse AI result
const aiOutput = $input.item.json.output;
const emailData = $('Format_For_AI1').item.json;

let aiResult;
try {
  const cleanText = aiOutput.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  aiResult = JSON.parse(cleanText);
} catch (e) {
  console.error('Failed to parse:', e.message);
  aiResult = { category: 'FYI', reason: 'Parse failed', confidence: 0.5 };
}

console.log(`✅ ${emailData.userEmail}: ${aiResult.category}`);

return {
  json: {
    emailId: emailData.emailId,
    category: aiResult.category,
    reason: aiResult.reason,
    confidence: aiResult.confidence,
    userId: emailData.userId,
    userEmail: emailData.userEmail,
    accessToken: emailData.accessToken,
    subject: emailData.subject
  }
};

// YOUR COMPREHENSIVE PII MASKING FUNCTION (keeping exactly as-is)
const email = $input.item.json;
const userCreds = $('Merge_Credentials1').item.json;

function maskSensitiveData(text) {
  if (!text) return text;

  let maskedText = text;

  const patterns = [
    {
      regex: /\b(Passport|Passport\s*Number|Passport\s*#|Travel\s*Document)[\s:]*[\r\n]*([A-Z]?[A-Z0-9]{6,9})\b/gi,
      replacement: (match, label) => `${label}: <PASSPORT>`
    },
    {
      regex: /\b(SSN|Social\s*Security\s*Number|Social\s*Security)[\s:]*[\r\n]*(\d{3}[-\s]?\d{2}[-\s]?\d{4})\b/gi,
      replacement: (match, label) => `${label}: <SSN>`
    },
    { regex: /\b\d{3}[-\s]?\d{2}[-\s]?\d{4}\b/g, replacement: '<SSN>' },
    {
      regex: /\b(EIN|Tax\s*ID|Employer\s*ID)[\s:]*[\r\n]*(\d{2}[-\s]\d{7})\b/gi,
      replacement: (match, label) => `${label}: <EIN>`
    },
    {
      regex: /\b(Driver'?s?\s*License|DL|License\s*Number|Driving\s*License)[\s:]*[\r\n]*([A-Z]{2}?\s*[A-Z0-9\s-]{5,20})\b/gi,
      replacement: (match, label) => `${label}: <LICENSE>`
    },
    {
      regex: /\b(National\s*ID|ID\s*Number|Citizen\s*ID)[\s:]*[\r\n]*([A-Z0-9\s-]{6,20})\b/gi,
      replacement: (match, label) => `${label}: <GOV_ID>`
    },
    {
      regex: /\b(DOB|Date\s*of\s*Birth|Birth\s*Date|Born|Birthday)[\s:]*[\r\n]*([A-Za-z]+\s+\d{1,2},?\s+\d{4})\b/gi,
      replacement: (match, label) => `${label}: <DOB>`
    },
    {
      regex: /\b(DOB|Date\s*of\s*Birth|Birth\s*Date|Born|Birthday)[\s:]*[\r\n]*(\d{1,2}[-/]\d{1,2}[-/]\d{2,4})\b/gi,
      replacement: (match, label) => `${label}: <DOB>`
    },
    { regex: /\b\d{1,2}[-/]\d{1,2}[-/]\d{2,4}\b/g, replacement: '<DATE>' },
    {
      regex: /\b(Phone|Telephone|Tel|Mobile|Cell|Contact)[\s:]*[\r\n]*(\+?1?[-.\s]?\(?\d{3}\)?[-.\s]?\d{3}[-.\s]?\d{4})\b/gi,
      replacement: (match, label) => `${label}: <PHONE>`
    },
    { regex: /\b\+?1?[-.\s]?\(?\d{3}\)?[-.\s]?\d{3}[-.\s]?\d{4}\b/g, replacement: '<PHONE>' },
    { regex: /\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b/g, replacement: '<EMAIL>' },
    { regex: /\b(?:\d{4}[-\s]?){3}\d{4}\b/g, replacement: '<CARD>' },
    {
      regex: /\b(Password|Pass\s*word)[\s:*=-]*(?:\r?\n+)?["'`]?(?!<PASSWORD>)([^\s\r\n,;<>"]{4,30})["'`]?/gi,
      replacement: (match, label, pwd) => match.includes('<PASSWORD>') ? match : match.replace(pwd, '<PASSWORD>')
    },
    {
      regex: /\b(Username|User\s*Name|Login)[\s:*=-]*(?:\r?\n+)?["'`]?(?!<USERNAME>)([^\s\r\n,;<>"]+)["'`]?/gi,
      replacement: (match, label, value) => match.includes('<USERNAME>') ? match : match.replace(value, '<USERNAME>')
    }
  ];

  patterns.forEach(({ regex, replacement }) => {
    maskedText = maskedText.replace(regex, replacement);
  });

  return maskedText;
}

// Extract sender
let senderEmail = '';
let senderDomain = '';

if (email.from) {
  if (typeof email.from === 'string') {
    senderEmail = email.from;
  } else if (email.from.emailAddress) {
    senderEmail = email.from.emailAddress.address || '';
  }
  senderDomain = senderEmail.split('@')[1] || '';
}

const maskedSubject = maskSensitiveData(email.subject || '');
const maskedBody = maskSensitiveData(email.bodyPreview || '');

const contentForAI = `Subject: ${maskedSubject}\nFrom: ${senderEmail}\nDomain: ${senderDomain}\nPreview: ${maskedBody}`;

console.log(`✅ Email prepared for user: ${userCreds.user_email}`);

return {
  json: {
    emailId: email.id,
    maskedSubject: maskedSubject,
    contentForAI: contentForAI,
    senderDomain: senderDomain,
    hasAttachments: email.hasAttachments || false,
    importance: email.importance || 'normal',
    receivedDateTime: email.receivedDateTime,
    containsPII: contentForAI.includes('<'),
    userId: userCreds.user_id,
    userEmail: userCreds.user_email,
    accessToken: userCreds.access_token
  }
};

// FIXED: Summarize Results Node Code
// This retrieves category data from Parse Classifications node

// Get the actual category data from Parse Classifications node
let categorizedEmails = [];
try {
  const parseNode = $('Parse Classifications2');
  if (parseNode && parseNode.all().length > 0) {
    categorizedEmails = parseNode.all().map(item => ({
      emailId: item.json.emailId,
      category: item.json.category,
      reason: item.json.reason,
      confidence: item.json.confidence,
      subject: item.json.subject
    }));
    console.log(`✓ Retrieved ${categorizedEmails.length} categorized emails`);
  }
} catch (e) {
  console.error('Failed to get Parse Classifications data:', e.message);
}

// If we couldn't get from Parse Classifications, try to reconstruct from current input
if (categorizedEmails.length === 0) {
  console.warn('Could not retrieve from Parse Classifications, using current input');
  categorizedEmails = $input.all().map(item => ({
    emailId: item.json.emailId || item.json.id,
    category: item.json.category || 'UNKNOWN',
    reason: item.json.reason || 'No reason provided',
    confidence: item.json.confidence || 0,
    subject: item.json.subject || 'No subject'
  }));
}

// Build summary
const summary = {
  total_processed: categorizedEmails.length,
  timestamp: new Date().toISOString(),
  by_category: {},
  emails: []
};

categorizedEmails.forEach(email => {
  const category = email.category;

  // Count by category
  if (!summary.by_category[category]) {
    summary.by_category[category] = 0;
  }
  summary.by_category[category]++;

  // Add to emails list
  summary.emails.push({
    subject: email.subject,
    category: category,
    reason: email.reason,
    confidence: email.confidence
  });
});

console.log('Summary by category:', summary.by_category);

return [{ json: summary }];

// Check_Token_Expiry node (corrected)
const credentials = $input.first().json;

// tokenExpiresAtUnix might be seconds (10 digits) or ms (13 digits)
let expiresAtMs = Number(credentials.token_expires_at_unix);

if (!Number.isFinite(expiresAtMs)) {
  // fallback to ISO string if Unix is missing/bad
  expiresAtMs = Date.parse(credentials.token_expires_at);
}

// If it's seconds (< 10^12), convert to milliseconds
if (expiresAtMs < 1e12) {
  expiresAtMs = expiresAtMs * 1000;
}

const nowMs = Date.now();
const timeUntilExpiryMs = expiresAtMs - nowMs;
const timeUntilExpirySec = Math.floor(timeUntilExpiryMs / 1000);

// Treat expired tokens as "needs refresh" too
const needsRefresh = timeUntilExpirySec <= 300; // <5 min OR already expired

console.log(`Token check for ${credentials.user_email}: ${timeUntilExpirySec}s remaining, refresh=${needsRefresh}`);

return [{
  json: {
    ...credentials,
    needsRefresh: needsRefresh,
    timeUntilExpiry: timeUntilExpirySec,
    tokenExpiresAtMs: expiresAtMs,
    nowMs: nowMs
  }
}];

// Calculate_New_Expiry node
const refreshData = $input.first().json;
const checkData = $('Check_Token_Expiry1').first().json;

const access_token = refreshData.access_token;
const refresh_token = refreshData.refresh_token || checkData.refresh_token;
const expires_in = refreshData.expires_in || 3600; // Microsoft returns this in SECONDS

// Store in SECONDS (not milliseconds)
const current_time = Math.floor(Date.now() / 1000); // SECONDS
const expires_at_unix = current_time + expires_in; // SECONDS
const expires_at_iso = new Date(expires_at_unix * 1000).toISOString(); // Convert to ms for ISO

console.log(`✅ Token refreshed for ${checkData.user_email}`);
console.log(`   New expiry: ${expires_at_unix} (${expires_at_iso})`);

return {
  user_id: checkData.user_id,
  user_email: checkData.user_email,
  user_name: checkData.user_name,
  outlook_credential_id: checkData.outlook_credential_id,
  timezone: checkData.timezone,
  webhook_url: checkData.webhook_url,
  is_active: checkData.is_active,
  access_token: access_token,
  refresh_token: refresh_token,
  token_expires_at: expires_at_iso,
  token_expires_at_unix: expires_at_unix, // Store as SECONDS
  last_refreshed: new Date().toISOString(),
  subscription_id: checkData.subscription_id,
  subscription_expires_at: checkData.subscription_expires_at,
  id: checkData.id,
  createdAt: checkData.createdAt,
  updatedAt: new Date().toISOString()
};

// Merge_Credentials node
// Ensures correct token is used regardless of which path was taken

const checkData = $('Check_Token_Expiry1').first().json;

// Try to get refreshed credentials from Update node
try {
  const updateData = $('Update row(s)1').first().json;

  if (updateData && updateData.access_token) {
    console.log(`✅ Using REFRESHED token for ${checkData.user_email}`);
    return {
      json: {
        user_id: checkData.user_id,
        user_email: checkData.user_email,
        access_token: updateData.access_token,
        refresh_token: updateData.refresh_token,
        // Include other necessary fields
      }
    };
  }
} catch (e) {
  // Update node didn't run (FALSE branch was taken)
  console.log(`ℹ️  Update node not executed, using existing token for ${checkData.user_email}`);
}

// Token was still valid, use original credentials
console.log(`✅ Using EXISTING token for ${checkData.user_email}`);
return {
  json: {
    user_id: checkData.user_id,
    user_email: checkData.user_email,
    access_token: checkData.access_token,
    refresh_token: checkData.refresh_token,
    // Include other necessary fields
  }
};

// Conditional_Response Code Node
const input = $input.first().json;

if (input.isValidation) {
  // Validation request - return validation token
  console.log('📝 Responding with validation token');

  return {
    json: {
      responseType: 'validation',
      validationToken: input.validationToken
    }
  };
} else {
  // Email notification - return immediate acknowledgment
  console.log('✅ Acknowledging email notification');

  return {
    json: {
      responseType: 'acknowledgment',
      status: 'accepted'
    }
  };
}
